   1→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
   2→import { Circle, Group, Image as KonvaImage, Layer, Line, Rect, Stage, Text } from "react-konva";
   3→import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
   4→import { addCanvasMargin, addCanvasStamp, deleteCanvasMargin, deleteCanvasStamp, getCanvasMargins, getCanvasStamps } from "../../../../API/Api";
   5→import { useAuth } from "../../../Context/useAuth";
   6→import supabase from "../../../utils/supabaseClient";
   7→import { parseCanvasDoc } from "../../../utils/canvasDoc";
   8→import "./canvas.css";
   9→
  10→const STAMP_ICONS = {
  11→    heart: "❤️",
  12→    star: "⭐",
  13→    question: "❓",
  14→    fire: "🔥"
  15→};
  16→
  17→const FONT_BRUSHES = {
  18→    serif: {fontFamily: "Georgia", fontStyle: "normal"},
  19→    mono: {fontFamily: "Courier New", fontStyle: "normal"},
  20→    handwritten: {fontFamily: "Comic Sans MS", fontStyle: "normal"},
  21→    bold: {fontFamily: "Trebuchet MS", fontStyle: "bold"},
  22→};
  23→
  24→const GRID_SIZE = 24;
  25→const CANVAS_MAX_WIDTH = 640;
  26→const CANVAS_ROOT_SNIPPET_ID = "canvas-root";
  27→const STAMP_SIZE = 34;
  28→const STAMP_FONT_SIZE = 30;
  29→const PROFILE_SIZE = 13;
  30→const STICKY_WIDTH = 172;
  31→const STICKY_HEIGHT = 118;
  32→const REALTIME_CHANNEL_SUFFIX_LENGTH = 8;
  33→const OPTIMISTIC_STAMP_PREFIX = "optimistic-stamp";
  34→const OPTIMISTIC_MARGIN_PREFIX = "optimistic-margin";
  35→const DOODLE_COLOR_PRESETS = [
  36→    "#5f92ff",
  37→    "#ff4d6d",
  38→    "#ff7f11",
  39→    "#ffd23f",
  40→    "#22c55e",
  41→    "#14b8a6",
  42→    "#8b5cf6",
  43→    "#111827",
  44→    "#ffffff"
  45→];
  46→const LIVE_DOODLE_BROADCAST_EVENT = "doodle-progress";
  47→const LIVE_DOODLE_END_EVENT = "doodle-end";
  48→const LIVE_DOODLE_BROADCAST_INTERVAL_MS = 40;
  49→const LIVE_DOODLE_STALE_MS = 2200;
  50→
  51→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
  52→const createOptimisticId = (prefix) => `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
  53→const toTimestamp = (value) => {
  54→    const parsed = Date.parse(value || "");
  55→    return Number.isNaN(parsed) ? 0 : parsed;
  56→};
  57→const sortByCreatedAt = (a, b) => {
  58→    const byDate = toTimestamp(a?.created_at) - toTimestamp(b?.created_at);
  59→    if(byDate !== 0){
  60→        return byDate;
  61→    }
  62→    return String(a?.id || "").localeCompare(String(b?.id || ""));
  63→};
  64→const sanitizeNormalizedPoints = (rawPoints) => {
  65→    if(!Array.isArray(rawPoints)){
  66→        return [];
  67→    }
  68→
  69→    const numericPoints = rawPoints
  70→        .map((point) => Number(point))
  71→        .filter((point) => !Number.isNaN(point))
  72→        .map((point) => clamp(point, 0, 1));
  73→
  74→    if(numericPoints.length < 2){
  75→        return [];
  76→    }
  77→
  78→    return numericPoints.length % 2 === 0
  79→        ? numericPoints
  80→        : numericPoints.slice(0, -1);
  81→};
  82→const getNameInitial = (name) => {
  83→    const normalizedName = typeof name === "string" ? name.trim() : "";
  84→    return normalizedName ? normalizedName.slice(0, 1).toUpperCase() : "?";
  85→};
  86→
  87→const getStageHeight = (width, aspectRatio) => {
  88→    if(aspectRatio === "4:5"){
  89→        return Math.round(width * 1.25);
  90→    }
  91→    return width;
  92→};
  93→
  94→const getSnippetMetrics = (snippet, stageWidth) => {
  95→    const sizeScale = Number.isFinite(snippet.sizeScale) ? snippet.sizeScale : 1;
  96→    const baseFontSize = snippet.fontStyle === "bold" ? 34 : snippet.fontStyle === "handwritten" ? 32 : 30;
  97→    const fontSize = clamp(baseFontSize * sizeScale, 18, 92);
  98→    const estimatedWidth = Math.max(120, Math.min(stageWidth * 0.78, Math.round((snippet.text.length || 1) * fontSize * 0.58)));
  99→    const charsPerLine = Math.max(8, Math.floor(estimatedWidth / (fontSize * 0.56)));
 100→    const lineCount = Math.max(1, Math.ceil((snippet.text.length || 1) / charsPerLine));
 101→    const height = Math.max(68, Math.round(lineCount * fontSize * 1.14 + 18));
 102→
 103→    return {width: estimatedWidth, height, fontSize};
 104→};
 105→
 106→const useLoadedImage = (src) => {
 107→    const [image, setImage] = useState(null);
 108→
 109→    useEffect(() => {
 110→        if(!src){
 111→            setImage(null);
 112→            return;
 113→        }
 114→
 115→        const img = new window.Image();
 116→        img.crossOrigin = "anonymous";
 117→        img.onload = () => setImage(img);
 118→        img.onerror = () => setImage(null);
 119→        img.src = src;
 120→
 121→        return () => {
 122→            img.onload = null;
 123→            img.onerror = null;
 124→        };
 125→    }, [src]);
 126→
 127→    return image;
 128→};
 129→
 130→const emojiCanvasCache = new Map();
 131→
 132→const useEmojiImage = (emoji, size) => {
 133→    const [image, setImage] = useState(null);
 134→
 135→    useEffect(() => {
 136→        if(!emoji){
 137→            setImage(null);
 138→            return;
 139→        }
 140→
 141→        const cacheKey = `${emoji}_${size}`;
 142→        if(emojiCanvasCache.has(cacheKey)){
 143→            setImage(emojiCanvasCache.get(cacheKey));
 144→            return;
 145→        }
 146→
 147→        const canvas = document.createElement("canvas");
 148→        const scale = window.devicePixelRatio || 1;
 149→        canvas.width = size * scale;
 150→        canvas.height = size * scale;
 151→        const ctx = canvas.getContext("2d");
 152→        ctx.scale(scale, scale);
 153→        ctx.textAlign = "center";
 154→        ctx.textBaseline = "middle";
 155→        ctx.font = `${size * 0.82}px "Apple Color Emoji", "Segoe UI Emoji", "Noto Color Emoji", "Android Emoji", sans-serif`;
 156→        ctx.fillText(emoji, size / 2, size / 2);
 157→
 158→        const img = new window.Image();
 159→        img.onload = () => {
 160→            emojiCanvasCache.set(cacheKey, img);
 161→            setImage(img);
 162→        };
 163→        img.src = canvas.toDataURL();
 164→    }, [emoji, size]);
 165→
 166→    return image;
 167→};
 168→
 169→const CanvasImageNode = ({canvasImage, stageWidth, stageHeight, onStamp}) => {
 170→    const loadedImage = useLoadedImage(canvasImage?.src);
 171→    const objectWidth = clamp((canvasImage?.width || 0.3) * stageWidth, 56, stageWidth * 0.95);
 172→    const objectHeight = clamp((canvasImage?.height || 0.3) * stageHeight, 56, stageHeight * 0.95);
 173→    const x = clamp((canvasImage?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - objectWidth));
 174→    const y = clamp((canvasImage?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - objectHeight));
 175→
 176→    return (
 177→        <KonvaImage
 178→            x={x}
 179→            y={y}
 180→            width={objectWidth}
 181→            height={objectHeight}
 182→            image={loadedImage}
 183→            rotation={canvasImage?.rotation || 0}
 184→            scaleX={canvasImage?.scaleX === -1 ? -1 : 1}
 185→            onClick={onStamp}
 186→            onTap={onStamp}
 187→        />
 188→    );
 189→};
 190→
 191→const StampNode = ({stamp, stageWidth, stageHeight, canDelete, onDelete}) => {
 192→    const avatarImage = useLoadedImage(stamp?.user_image_url);
 193→    const icon = STAMP_ICONS[stamp?.stamp_type] || "✨";
 194→    const emojiImage = useEmojiImage(icon, STAMP_SIZE);
 195→    const stampX = clamp((stamp?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - STAMP_SIZE));
 196→    const stampY = clamp((stamp?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - (STAMP_SIZE + PROFILE_SIZE + 10)));
 197→    const avatarCenterX = stampX + (STAMP_SIZE / 2);
 198→    const avatarCenterY = stampY + STAMP_SIZE + (PROFILE_SIZE / 2) + 6;
 199→    const avatarRadius = PROFILE_SIZE / 2;
 200→
 201→    const handleDelete = () => {
 202→        if(canDelete){
 203→            onDelete();
 204→        }
 205→    };
 206→
 207→    return (
 208→        <Group onClick={handleDelete} onTap={handleDelete}>
 209→            <Circle
 210→                x={stampX + (STAMP_SIZE / 2)}
 211→                y={stampY + (STAMP_SIZE / 2)}
 212→                radius={(STAMP_SIZE / 2) + 1.8}
 213→                fill="rgba(255,255,255,0.78)"
 214→                shadowColor="rgba(0,0,0,0.22)"
 215→                shadowBlur={5}
 216→                shadowOffsetY={2}
 217→                listening={false}
 218→            />
 219→            {emojiImage ? (
 220→                <KonvaImage
 221→                    x={stampX}
 222→                    y={stampY}
 223→                    width={STAMP_SIZE}
 224→                    height={STAMP_SIZE}
 225→                    image={emojiImage}
 226→                    listening={false}
 227→                />
 228→            ) : (
 229→                <Text
 230→                    x={stampX}
 231→                    y={stampY}
 232→                    width={STAMP_SIZE}
 233→                    height={STAMP_SIZE}
 234→                    text={icon}
 235→                    fontSize={STAMP_FONT_SIZE}
 236→                    align="center"
 237→                    verticalAlign="middle"
 238→                    listening={false}
 239→                />
 240→            )}
 241→            <Circle
 242→                x={avatarCenterX}
 243→                y={avatarCenterY}
 244→                radius={avatarRadius + 1.2}
 245→                fill="rgba(0,0,0,0.22)"
 246→                listening={false}
 247→            />
 248→            {avatarImage ? (
 249→                <Group
 250→                    clipFunc={(ctx) => {
 251→                        ctx.arc(avatarCenterX, avatarCenterY, avatarRadius, 0, Math.PI * 2, false);
 252→                    }}
 253→                    listening={false}
 254→                >
 255→                    <KonvaImage
 256→                        x={avatarCenterX - avatarRadius}
 257→                        y={avatarCenterY - avatarRadius}
 258→                        width={PROFILE_SIZE}
 259→                        height={PROFILE_SIZE}
 260→                        image={avatarImage}
 261→                        listening={false}
 262→                    />
 263→                </Group>
 264→            ) : (
 265→                <>
 266→                    <Circle
 267→                        x={avatarCenterX}
 268→                        y={avatarCenterY}
 269→                        radius={avatarRadius}
 270→                        fill="#c9d0dc"
 271→                        stroke="rgba(255,255,255,0.95)"
 272→                        strokeWidth={0.7}
 273→                        listening={false}
 274→                    />
 275→                    <Text
 276→                        x={avatarCenterX - avatarRadius}
 277→                        y={avatarCenterY - avatarRadius}
 278→                        width={PROFILE_SIZE}
 279→                        height={PROFILE_SIZE}
 280→                        text={getNameInitial(stamp?.user_name)}
 281→                        fontSize={8}
 282→                        fontStyle="bold"
 283→                        fill="#1f2c3f"
 284→                        align="center"
 285→                        verticalAlign="middle"
 286→                        listening={false}
 287→                    />
 288→                </>
 289→            )}
 290→        </Group>
 291→    );
 292→};
