 294→const CanvasViewer = ({journalId, canvasDoc, authorId}) => {
 295→    const {session, user, openAuthModal} = useAuth();
 296→    const queryClient = useQueryClient();
 297→    const shellRef = useRef(null);
 298→    const stageRef = useRef(null);
 299→    const viewerClientIdRef = useRef(createOptimisticId("canvas-client"));
 300→    const realtimeChannelRef = useRef(null);
 301→    const currentDoodlePointsRef = useRef([]);
 302→    const pendingDoodlePayloadRef = useRef(null);
 303→    const doodleBroadcastTimerRef = useRef(null);
 304→    const lastDoodleBroadcastAtRef = useRef(0);
 305→
 306→    const [shellWidth, setShellWidth] = useState(CANVAS_MAX_WIDTH);
 307→    const [activeStampType, setActiveStampType] = useState("heart");
 308→    const [activeTool, setActiveTool] = useState("stamp");
 309→    const [draggingStampType, setDraggingStampType] = useState("");
 310→    const [isDropActive, setIsDropActive] = useState(false);
 311→    const [doodleColor, setDoodleColor] = useState("#5f92ff");
 312→    const [doodleSize, setDoodleSize] = useState(2.8);
 313→    const [isDrawing, setIsDrawing] = useState(false);
 314→    const [currentDoodlePoints, setCurrentDoodlePoints] = useState([]);
 315→    const [liveDoodlesByClient, setLiveDoodlesByClient] = useState({});
 316→
 317→    const parsedCanvasDoc = useMemo(() => parseCanvasDoc(canvasDoc), [canvasDoc]);
 318→    const sortedObjects = useMemo(() => {
 319→        const textObjects = (parsedCanvasDoc.snippets || []).map((snippet) => ({kind: "snippet", payload: snippet}));
 320→        const imageObjects = (parsedCanvasDoc.images || []).map((image) => ({kind: "image", payload: image}));
 321→        return [...textObjects, ...imageObjects].sort((a, b) => (a.payload?.zIndex || 0) - (b.payload?.zIndex || 0));
 322→    }, [parsedCanvasDoc.images, parsedCanvasDoc.snippets]);
 323→
 324→    useEffect(() => {
 325→        const getContentWidth = () => {
 326→            const el = shellRef.current;
 327→            if(!el){
 328→                return CANVAS_MAX_WIDTH;
 329→            }
 330→            const style = getComputedStyle(el);
 331→            const paddingLeft = parseFloat(style.paddingLeft) || 0;
 332→            const paddingRight = parseFloat(style.paddingRight) || 0;
 333→            return el.clientWidth - paddingLeft - paddingRight;
 334→        };
 335→
 336→        const updateShellWidth = () => {
 337→            setShellWidth(getContentWidth());
 338→        };
 339→
 340→        updateShellWidth();
 341→        window.addEventListener("resize", updateShellWidth);
 342→
 343→        let resizeObserver = null;
 344→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
 345→            resizeObserver = new ResizeObserver(updateShellWidth);
 346→            resizeObserver.observe(shellRef.current);
 347→        }
 348→
 349→        return () => {
 350→            window.removeEventListener("resize", updateShellWidth);
 351→            if(resizeObserver){
 352→                resizeObserver.disconnect();
 353→            }
 354→        };
 355→    }, []);
 356→
 357→    const stageWidth = useMemo(() => Math.max(240, Math.min(CANVAS_MAX_WIDTH, shellWidth)), [shellWidth]);
 358→    const stageHeight = getStageHeight(stageWidth, parsedCanvasDoc?.meta?.aspectRatio);
 359→
 360→    const {data: stampData} = useQuery({
 361→        queryKey: ["canvasStamps", journalId],
 362→        queryFn: () => getCanvasStamps(journalId, session?.access_token),
 363→        enabled: !!journalId,
 364→        refetchOnWindowFocus: false
 365→    });
 366→
 367→    const {data: marginData} = useQuery({
 368→        queryKey: ["canvasMargins", journalId],
 369→        queryFn: () => getCanvasMargins(journalId, session?.access_token),
 370→        enabled: !!journalId,
 371→        refetchOnWindowFocus: false
 372→    });
 373→
 374→    const stampsQueryKey = useMemo(() => ["canvasStamps", journalId], [journalId]);
 375→    const marginsQueryKey = useMemo(() => ["canvasMargins", journalId], [journalId]);
 376→    const currentUserProfile = user?.userData?.[0] || null;
 377→    const currentUserId = currentUserProfile?.id || null;
 378→    const canUseDoodle = Boolean(currentUserId && String(currentUserId) === String(authorId));
 379→
 380→    useEffect(() => {
 381→        if(!canUseDoodle && activeTool === "doodle"){
 382→            setActiveTool("stamp");
 383→            setIsDrawing(false);
 384→            setCurrentDoodlePoints([]);
 385→            currentDoodlePointsRef.current = [];
 386→        }
 387→    }, [activeTool, canUseDoodle]);
 388→
 389→    const getKnownUserProfile = useCallback((targetUserId) => {
 390→        if(!targetUserId){
 391→            return {user_name: null, user_image_url: null};
 392→        }
 393→
 394→        if(currentUserProfile?.id === targetUserId){
 395→            return {
 396→                user_name: currentUserProfile?.name || null,
 397→                user_image_url: currentUserProfile?.image_url || null
 398→            };
 399→        }
 400→
 401→        const knownStamps = queryClient.getQueryData(stampsQueryKey)?.stamps || [];
 402→        const knownMargins = queryClient.getQueryData(marginsQueryKey)?.items || [];
 403→        const match = [...knownStamps, ...knownMargins].find((item) => (
 404→            item?.user_id === targetUserId && (item?.user_name || item?.user_image_url)
 405→        ));
 406→
 407→        return {
 408→            user_name: match?.user_name || null,
 409→            user_image_url: match?.user_image_url || null
 410→        };
 411→    }, [currentUserProfile?.id, currentUserProfile?.image_url, currentUserProfile?.name, marginsQueryKey, queryClient, stampsQueryKey]);
 412→
 413→    const normalizeStampRow = useCallback((row) => {
 414→        if(!row?.id){
 415→            return null;
 416→        }
 417→        const knownProfile = getKnownUserProfile(row.user_id);
 418→        return {
 419→            id: row.id,
 420→            journal_id: row.journal_id,
 421→            user_id: row.user_id,
 422→            snippet_id: row.snippet_id,
 423→            word_key: row.word_key,
 424→            stamp_type: row.stamp_type,
 425→            x: row.x,
 426→            y: row.y,
 427→            created_at: row.created_at,
 428→            user_name: row.user_name ?? knownProfile.user_name ?? null,
 429→            user_image_url: row.user_image_url ?? knownProfile.user_image_url ?? null
 430→        };
 431→    }, [getKnownUserProfile]);
 432→
 433→    const normalizeMarginRow = useCallback((row) => {
 434→        if(!row?.id){
 435→            return null;
 436→        }
 437→        const knownProfile = getKnownUserProfile(row.user_id);
 438→        return {
 439→            id: row.id,
 440→            journal_id: row.journal_id,
 441→            user_id: row.user_id,
 442→            item_type: row.item_type,
 443→            payload: row.payload || null,
 444→            created_at: row.created_at,
 445→            updated_at: row.updated_at,
 446→            user_name: row.user_name ?? knownProfile.user_name ?? null,
 447→            user_image_url: row.user_image_url ?? knownProfile.user_image_url ?? null
 448→        };
 449→    }, [getKnownUserProfile]);
 450→
 451→    const upsertStampCache = useCallback((stamp) => {
 452→        if(!stamp?.id){
 453→            return;
 454→        }
 455→
 456→        queryClient.setQueryData(stampsQueryKey, (old) => {
 457→            const previous = Array.isArray(old?.stamps) ? old.stamps : [];
 458→            const existingIndex = previous.findIndex((item) => String(item?.id) === String(stamp.id));
 459→            let nextStamps = previous;
 460→
 461→            if(existingIndex === -1){
 462→                nextStamps = [...previous, stamp];
 463→            } else {
 464→                nextStamps = [...previous];
 465→                nextStamps[existingIndex] = {...nextStamps[existingIndex], ...stamp};
 466→            }
 467→
 468→            nextStamps.sort(sortByCreatedAt);
 469→            return {...(old || {}), stamps: nextStamps};
 470→        });
 471→    }, [queryClient, stampsQueryKey]);
 472→
 473→    const upsertMarginCache = useCallback((item) => {
 474→        if(!item?.id){
 475→            return;
 476→        }
 477→
 478→        queryClient.setQueryData(marginsQueryKey, (old) => {
 479→            const previous = Array.isArray(old?.items) ? old.items : [];
 480→            const existingIndex = previous.findIndex((entry) => String(entry?.id) === String(item.id));
 481→            let nextItems = previous;
 482→
 483→            if(existingIndex === -1){
 484→                nextItems = [...previous, item];
 485→            } else {
 486→                nextItems = [...previous];
 487→                nextItems[existingIndex] = {...nextItems[existingIndex], ...item};
 488→            }
 489→
 490→            nextItems.sort(sortByCreatedAt);
 491→            return {...(old || {}), items: nextItems};
 492→        });
 493→    }, [marginsQueryKey, queryClient]);
 494→
 495→    const removeStampFromCache = useCallback((stampId) => {
 496→        if(!stampId){
 497→            return null;
 498→        }
 499→
 500→        let removedStamp = null;
 501→        queryClient.setQueryData(stampsQueryKey, (old) => {
 502→            const previous = Array.isArray(old?.stamps) ? old.stamps : [];
 503→            removedStamp = previous.find((item) => String(item?.id) === String(stampId)) || null;
 504→            const nextStamps = previous.filter((item) => String(item?.id) !== String(stampId));
 505→            return {...(old || {}), stamps: nextStamps};
 506→        });
 507→        return removedStamp;
 508→    }, [queryClient, stampsQueryKey]);
 509→
 510→    const removeMarginFromCache = useCallback((marginId) => {
 511→        if(!marginId){
 512→            return null;
 513→        }
 514→
 515→        let removedItem = null;
 516→        queryClient.setQueryData(marginsQueryKey, (old) => {
 517→            const previous = Array.isArray(old?.items) ? old.items : [];
 518→            removedItem = previous.find((entry) => String(entry?.id) === String(marginId)) || null;
 519→            const nextItems = previous.filter((entry) => String(entry?.id) !== String(marginId));
 520→            return {...(old || {}), items: nextItems};
 521→        });
 522→        return removedItem;
 523→    }, [marginsQueryKey, queryClient]);
 524→
 525→    const eventBelongsToJournal = useCallback((payload) => {
 526→        const journalIdAsString = String(journalId);
 527→        const newJournalId = payload?.new?.journal_id;
 528→        const oldJournalId = payload?.old?.journal_id;
 529→
 530→        if(newJournalId !== undefined){
 531→            return String(newJournalId) === journalIdAsString;
 532→        }
 533→        if(oldJournalId !== undefined){
 534→            return String(oldJournalId) === journalIdAsString;
 535→        }
 536→        return null;
 537→    }, [journalId]);
 538→
 539→    const clearQueuedDoodleBroadcast = useCallback(() => {
 540→        if(doodleBroadcastTimerRef.current){
 541→            clearTimeout(doodleBroadcastTimerRef.current);
 542→            doodleBroadcastTimerRef.current = null;
 543→        }
 544→    }, []);
 545→
 546→    const sendBroadcastEvent = useCallback((eventName, payload) => {
 547→        const channel = realtimeChannelRef.current;
 548→        if(!channel){
 549→            return;
 550→        }
 551→
 552→        channel.send({
 553→            type: "broadcast",
 554→            event: eventName,
 555→            payload: payload
 556→        }).catch((error) => {
 557→            console.error("Failed to send canvas broadcast event:", error);
 558→        });
 559→    }, []);
 560→
 561→    const flushQueuedDoodleBroadcast = useCallback(() => {
 562→        if(!pendingDoodlePayloadRef.current){
 563→            return;
 564→        }
 565→
 566→        const nextPayload = pendingDoodlePayloadRef.current;
 567→        pendingDoodlePayloadRef.current = null;
 568→        lastDoodleBroadcastAtRef.current = Date.now();
 569→        sendBroadcastEvent(LIVE_DOODLE_BROADCAST_EVENT, nextPayload);
 570→    }, [sendBroadcastEvent]);
 571→
 572→    const queueDoodleBroadcast = useCallback((payload, immediate = false) => {
 573→        pendingDoodlePayloadRef.current = payload;
 574→        if(immediate){
 575→            clearQueuedDoodleBroadcast();
 576→            flushQueuedDoodleBroadcast();
 577→            return;
 578→        }
 579→
 580→        const elapsed = Date.now() - lastDoodleBroadcastAtRef.current;
 581→        const delay = Math.max(0, LIVE_DOODLE_BROADCAST_INTERVAL_MS - elapsed);
 582→        if(doodleBroadcastTimerRef.current){
 583→            return;
 584→        }
 585→
 586→        doodleBroadcastTimerRef.current = setTimeout(() => {
 587→            doodleBroadcastTimerRef.current = null;
