 489→
 490→    const setItemsCache = useCallback((updater) => {
 491→        if(!weekId){
 492→            return;
 493→        }
 494→
 495→        queryClient.setQueryData(itemsQueryKey, (old) => {
 496→            const previousItems = Array.isArray(old?.data) ? old.data : [];
 497→            const nextItems = sortItemsByZIndex(updater(previousItems));
 498→            return {
 499→                ...(old || {}),
 500→                data: nextItems,
 501→                hasMore: false,
 502→                nextCursor: null
 503→            };
 504→        });
 505→    }, [itemsQueryKey, queryClient, weekId]);
 506→
 507→    const createItemMutation = useMutation({
 508→        mutationFn: ({payload}) => createFreedomWallItem(authToken, payload),
 509→        onMutate: async({payload}) => {
 510→            const optimisticId = `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
 511→            const optimisticItem = {
 512→                id: optimisticId,
 513→                week_id: payload.weekId,
 514→                user_id: currentUserId,
 515→                item_type: payload.itemType,
 516→                payload: payload.payload,
 517→                z_index: payload.zIndex || 0,
 518→                created_at: new Date().toISOString(),
 519→                updated_at: new Date().toISOString(),
 520→                deleted_at: null,
 521→                users: currentUser ? {
 522→                    id: currentUser.id,
 523→                    name: currentUser.name,
 524→                    image_url: currentUser.image_url,
 525→                    badge: currentUser.badge
 526→                } : null
 527→            };
 528→
 529→            setItemsCache((items) => [...items, optimisticItem]);
 530→            return {optimisticId: optimisticId};
 531→        },
 532→        onSuccess: (response, _variables, context) => {
 533→            const createdItem = response?.item;
 534→            if(!createdItem?.id){
 535→                return;
 536→            }
 537→
 538→            setItemsCache((items) => {
 539→                const withoutOptimistic = context?.optimisticId
 540→                    ? removeById(items, context.optimisticId)
 541→                    : items;
 542→                return upsertById(withoutOptimistic, createdItem);
 543→            });
 544→        },
 545→        onError: (error, variables, context) => {
 546→            console.error("Freedom Wall create error:", error, "variables:", variables);
 547→            if(context?.optimisticId){
 548→                setItemsCache((items) => removeById(items, context.optimisticId));
 549→            }
 550→            const message = error?.message || error?.error || "Failed to place item";
 551→            setWallError(message);
 552→            setTimeout(() => setWallError((prev) => prev === message ? null : prev), 4000);
 553→        }
 554→    });
 555→
 556→    const updateItemMutation = useMutation({
 557→        mutationFn: ({itemId, payload}) => updateFreedomWallItem(authToken, itemId, payload),
 558→        onMutate: async({itemId, payload}) => {
 559→            let previousItem = null;
 560→            setItemsCache((items) => {
 561→                previousItem = items.find((item) => String(item?.id) === String(itemId)) || null;
 562→                if(!previousItem){
 563→                    return items;
 564→                }
 565→
 566→                return items.map((item) => {
 567→                    if(String(item?.id) !== String(itemId)){
 568→                        return item;
 569→                    }
 570→
 571→                    const mergedPayload = payload?.payload !== undefined
 572→                        ? {...(item?.payload || {}), ...(payload.payload || {})}
 573→                        : item?.payload;
 574→
 575→                    return {
 576→                        ...item,
 577→                        payload: mergedPayload,
 578→                        z_index: payload?.zIndex !== undefined ? payload.zIndex : item?.z_index
 579→                    };
 580→                });
 581→            });
 582→            return {previousItem: previousItem};
 583→        },
 584→        onSuccess: (response) => {
 585→            const updatedItem = response?.item;
 586→            if(!updatedItem?.id){
 587→                return;
 588→            }
 589→
 590→            setItemsCache((items) => upsertById(items, updatedItem));
 591→        },
 592→        onError: (_error, variables, context) => {
 593→            if(!context?.previousItem){
 594→                return;
 595→            }
 596→
 597→            setItemsCache((items) => upsertById(items, context.previousItem));
 598→            if(variables?.itemId){
 599→                setSelectedItemId(String(variables.itemId));
 600→            }
 601→        }
 602→    });
 603→
 604→    const deleteItemMutation = useMutation({
 605→        mutationFn: ({itemId}) => deleteFreedomWallItem(authToken, itemId),
 606→        onMutate: async({itemId}) => {
 607→            let removedItem = null;
 608→            setItemsCache((items) => {
 609→                removedItem = items.find((item) => String(item?.id) === String(itemId)) || null;
 610→                return removeById(items, itemId);
 611→            });
 612→            return {removedItem: removedItem};
 613→        },
 614→        onError: (_error, _variables, context) => {
 615→            if(!context?.removedItem){
 616→                return;
 617→            }
 618→            setItemsCache((items) => upsertById(items, context.removedItem));
 619→        }
 620→    });
 621→
 622→    useEffect(() => {
 623→        if(!weekId){
 624→            return;
 625→        }
 626→
 627→        const channel = supabase
 628→            .channel(`freedom-wall-${weekId}`)
 629→            .on(
 630→                "postgres_changes",
 631→                {event: "*", schema: "public", table: "freedom_wall_items", filter: `week_id=eq.${weekId}`},
 632→                (payload) => {
 633→                    const eventType = payload?.eventType;
 634→                    const oldRow = payload?.old || null;
 635→                    const newRow = payload?.new || null;
 636→
 637→                    if(eventType === "DELETE" && oldRow?.id){
 638→                        setItemsCache((items) => removeById(items, oldRow.id));
 639→                        return;
 640→                    }
 641→
 642→                    if(!newRow?.id){
 643→                        return;
 644→                    }
 645→
 646→                    if(newRow?.deleted_at){
 647→                        setItemsCache((items) => removeById(items, newRow.id));
 648→                        return;
 649→                    }
 650→
 651→                    setItemsCache((items) => {
 652→                        const previous = items.find((item) => String(item?.id) === String(newRow.id)) || null;
 653→                        const fallbackUsers = previous?.users || (currentUserId && String(newRow.user_id) === String(currentUserId)
 654→                            ? {
 655→                                id: currentUser?.id,
 656→                                name: currentUser?.name,
 657→                                image_url: currentUser?.image_url,
 658→                                badge: currentUser?.badge
 659→                            }
 660→                            : null);
 661→                        const normalized = {
 662→                            ...newRow,
 663→                            users: fallbackUsers
 664→                        };
 665→
 666→                        return upsertById(items, normalized);
 667→                    });
 668→                }
 669→            )
 670→            .subscribe();
 671→
 672→        return () => {
 673→            supabase.removeChannel(channel);
 674→        };
 675→    }, [currentUser?.badge, currentUser?.id, currentUser?.image_url, currentUser?.name, currentUserId, setItemsCache, weekId]);
 676→
 677→    const ensureCanWrite = useCallback(() => {
 678→        if(canWrite){
 679→            return true;
 680→        }
 681→        openAuthModal?.();
 682→        return false;
 683→    }, [canWrite, openAuthModal]);
 684→
 685→    const getNormalizedPointerPosition = (stage, snap = false) => {
 686→        const pointer = stage?.getPointerPosition();
 687→        if(!pointer){
 688→            return null;
 689→        }
 690→
 691→        const px = snap ? snapToGrid(pointer.x) : pointer.x;
 692→        const py = snap ? snapToGrid(pointer.y) : pointer.y;
 693→
 694→        return {
 695→            x: clamp(px / stageWidth, 0, 1),
 696→            y: clamp(py / stageHeight, 0, 1)
 697→        };
 698→    };
 699→
 700→    const createWallItem = useCallback((itemType, payload) => {
 701→        if(!weekId || !ensureCanWrite()){
 702→            return;
 703→        }
 704→
 705→        createItemMutation.mutate({
 706→            payload: {
 707→                weekId: weekId,
 708→                itemType: itemType,
 709→                payload: payload,
 710→                zIndex: maxZIndex + 1
 711→            }
 712→        });
 713→    }, [createItemMutation, ensureCanWrite, maxZIndex, weekId]);
 714→
 715→    const handlePlaceItem = useCallback((stage) => {
 716→        const pointer = getNormalizedPointerPosition(stage);
 717→        if(!pointer){
 718→            return;
 719→        }
 720→
 721→        if(activeTool === "sticker"){
 722→            if(draftSticker || !selectedSticker){
 723→                return;
 724→            }
 725→
 726→            setDraftSticker({
 727→                sticker: selectedSticker,
 728→                x: pointer.x,
 729→                y: pointer.y,
 730→                scale: 1,
 731→                rotation: 0
 732→            });
 733→            return;
 734→        }
 735→
 736→        if(activeTool === "stamp"){
 737→            if(draftStamp){
 738→                return;
 739→            }
 740→
 741→            setDraftStamp({
 742→                stamp: selectedStamp,
 743→                x: pointer.x,
 744→                y: pointer.y,
 745→                scale: 1,
 746→                rotation: 0
 747→            });
 748→            return;
 749→        }
 750→
 751→        if(activeTool === "note"){
 752→            if(draftNote){
 753→                return;
 754→            }
 755→            setDraftNote({
 756→                x: pointer.x,
 757→                y: pointer.y,
 758→                text: "",
 759→                fontFamily: "Arial",
 760→                fontStyle: "normal",
 761→                fontColor: "#1f2937",
 762→                bgColor: "#fff4a8",
 763→                fontSize: 16
