 767→
 768→    const handleStagePointerDown = (event) => {
 769→        const stage = event.target.getStage();
 770→        if(!stage){
 771→            return;
 772→        }
 773→
 774→        if(activeTool === "doodle"){
 775→            if(!ensureCanWrite()){
 776→                return;
 777→            }
 778→
 779→            const normalizedPointer = getNormalizedPointerPosition(stage);
 780→            if(!normalizedPointer){
 781→                return;
 782→            }
 783→
 784→            setSelectedItemId(null);
 785→            const initialPoints = [normalizedPointer.x, normalizedPointer.y];
 786→            draftDoodleRef.current = initialPoints;
 787→            setDraftDoodlePoints(initialPoints);
 788→            setIsDrawing(true);
 789→            if(event?.evt?.cancelable){
 790→                event.evt.preventDefault();
 791→            }
 792→            return;
 793→        }
 794→
 795→        if(activeTool === "stamp"){
 796→            if(draftStamp){
 797→                return;
 798→            }
 799→
 800→            if(!ensureCanWrite()){
 801→                return;
 802→            }
 803→
 804→            setSelectedItemId(null);
 805→            handlePlaceItem(stage);
 806→            if(event?.evt?.cancelable){
 807→                event.evt.preventDefault();
 808→            }
 809→            return;
 810→        }
 811→
 812→        if(isCanvasBackgroundTarget(event.target, stage)){
 813→            setSelectedItemId(null);
 814→            const canPlaceSticker = activeTool === "sticker" && !draftSticker;
 815→            const canPlaceNote = activeTool === "note" && !draftNote;
 816→            if(canPlaceSticker || canPlaceNote){
 817→                handlePlaceItem(stage);
 818→            }
 819→        }
 820→    };
 821→
 822→    const handleStagePointerMove = (event) => {
 823→        if(activeTool !== "doodle" || !isDrawing){
 824→            return;
 825→        }
 826→
 827→        const stage = event.target.getStage();
 828→        const normalizedPointer = getNormalizedPointerPosition(stage);
 829→        if(!normalizedPointer){
 830→            return;
 831→        }
 832→
 833→        const nextPoints = [...draftDoodleRef.current, normalizedPointer.x, normalizedPointer.y];
 834→        draftDoodleRef.current = nextPoints;
 835→        setDraftDoodlePoints(nextPoints);
 836→        if(event?.evt?.cancelable){
 837→            event.evt.preventDefault();
 838→        }
 839→    };
 840→
 841→    const handleStagePointerUp = () => {
 842→        if(activeTool !== "doodle"){
 843→            return;
 844→        }
 845→
 846→        const points = draftDoodleRef.current
 847→            .map((point) => Number(point))
 848→            .filter((point) => !Number.isNaN(point))
 849→            .map((point) => clamp(point, 0, 1));
 850→
 851→        if(points.length >= 4){
 852→            const normalizedPoints = points.length % 2 === 0 ? points : points.slice(0, -1);
 853→            createWallItem("doodle", {
 854→                points: normalizedPoints,
 855→                color: doodleColor,
 856→                size: doodleSize
 857→            });
 858→        }
 859→
 860→        setIsDrawing(false);
 861→        setDraftDoodlePoints([]);
 862→        draftDoodleRef.current = [];
 863→    };
 864→
 865→    const handleDeleteSelectedItem = () => {
 866→        if(!selectedItem || !selectedItemCanEdit){
 867→            return;
 868→        }
 869→
 870→        deleteItemMutation.mutate({itemId: selectedItem.id});
 871→        setSelectedItemId(null);
 872→    };
 873→
 874→    const handleDraftNoteSave = () => {
 875→        if(!draftNote){
 876→            return;
 877→        }
 878→
 879→        const noteText = draftNote.text?.trim();
 880→        if(!noteText){
 881→            return;
 882→        }
 883→
 884→        createWallItem("note", {
 885→            text: noteText,
 886→            x: draftNote.x,
 887→            y: draftNote.y,
 888→            width: 0.26,
 889→            height: 0.2,
 890→            rotation: 0,
 891→            fontFamily: draftNote.fontFamily || "Arial",
 892→            fontStyle: draftNote.fontStyle || "normal",
 893→            fontColor: draftNote.fontColor || "#1f2937",
 894→            bgColor: draftNote.bgColor || "#fff4a8",
 895→            fontSize: clamp(Number(draftNote.fontSize) || 16, 10, 64)
 896→        });
 897→
 898→        setDraftNote(null);
 899→    };
 900→
 901→    const handleDraftStickerSave = () => {
 902→        if(!draftSticker){
 903→            return;
 904→        }
 905→
 906→        createWallItem("sticker", {
 907→            sticker: draftSticker.sticker,
 908→            x: draftSticker.x,
 909→            y: draftSticker.y,
 910→            scale: clamp(Number(draftSticker.scale) || 1, 0.25, 6),
 911→            rotation: 0
 912→        });
 913→
 914→        setDraftSticker(null);
 915→    };
 916→
 917→    const handleDraftStampSave = () => {
 918→        if(!draftStamp){
 919→            return;
 920→        }
 921→
 922→        createWallItem("stamp", {
 923→            stamp: draftStamp.stamp,
 924→            x: draftStamp.x,
 925→            y: draftStamp.y,
 926→            scale: clamp(Number(draftStamp.scale) || 1, 0.35, 5),
 927→            rotation: 0
 928→        });
 929→
 930→        setDraftStamp(null);
 931→    };
 932→
 933→    const applyNoteChanges = () => {
 934→        if(!selectedNote || !selectedItemCanEdit){
 935→            return;
 936→        }
 937→
 938→        const nextText = noteEditor.text.trim();
 939→        if(!nextText){
 940→            return;
 941→        }
 942→
 943→        updateItemMutation.mutate({
 944→            itemId: selectedNote.id,
 945→            payload: {
 946→                payload: {
 947→                    text: nextText,
 948→                    fontFamily: noteEditor.fontFamily,
 949→                    fontStyle: noteEditor.fontStyle,
 950→                    fontColor: noteEditor.fontColor,
 951→                    bgColor: noteEditor.bgColor,
 952→                    fontSize: clamp(Number(noteEditor.fontSize) || 16, 10, 64)
 953→                }
 954→            }
 955→        });
 956→    };
 957→
 958→    const moveItemFromDrag = (item, event) => {
 959→        if(!selectedItemCanEdit || String(selectedItem?.id) !== String(item?.id)){
 960→            return;
 961→        }
